import React, { useEffect, useMemo, useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import './Header.css';

const navItems = [
  { label: '서비스 소개', section: 'features' },
  { label: '이용 방법', section: 'how-it-works' },
  { label: '요금 안내', section: 'pricing' },
  { label: 'FAQ', section: 'faq' },
];

export default function Header() {
  const location = useLocation();
  const { isLoggedIn } = useAuth();
  const [mobileOpen, setMobileOpen] = useState(false);

  const isHome = useMemo(() => location.pathname === '/', [location.pathname]);

  const getSectionHref = (section) => {
    return isHome ? `#${section}` : `/#${section}`;
  };

  useEffect(() => {
    const handleEsc = (e) => {
      if (e.key === 'Escape') setMobileOpen(false);
    };

    document.addEventListener('keydown', handleEsc);
    return () => document.removeEventListener('keydown', handleEsc);
  }, []);

  useEffect(() => {
    document.body.style.overflow = mobileOpen ? 'hidden' : '';
    return () => {
      document.body.style.overflow = '';
    };
  }, [mobileOpen]);

  useEffect(() => {
    setMobileOpen(false);
  }, [location.pathname]);

  return (
    <>
      <header className="matey-header">
        <div className="matey-header__inner">
          <Link to="/" className="matey-header__brand" aria-label="메인으로 이동">
            <div className="matey-header__brand-mark">
              <img src="/images/rabbit-duo.png" alt="마음친구 토끼와 고양이 캐릭터" />
            </div>

            <div className="matey-header__brand-text">
              <strong>마음친구</strong>
              <span>virtual care companion</span>
            </div>
          </Link>

          <nav className="matey-header__nav" aria-label="메인 메뉴">
            {navItems.map((item) => (
              <a key={item.label} href={getSectionHref(item.section)} className="matey-header__nav-link">
                {item.label}
              </a>
            ))}
          </nav>

          <div className="matey-header__actions">
            {isLoggedIn ? (
              <Link to="/dashboard" className="matey-header__btn matey-header__btn--ghost">
                대시보드
              </Link>
            ) : (
              <Link to="/login" className="matey-header__login">
                로그인
              </Link>
            )}

            <Link
              to={isLoggedIn ? '/chat' : '/signup'}
              className="matey-header__btn matey-header__btn--primary"
            >
              {isLoggedIn ? '대화 시작하기' : '무료 시작하기'}
            </Link>

            <button
              type="button"
              className={`matey-header__menu-toggle ${mobileOpen ? 'is-open' : ''}`}
              aria-label="모바일 메뉴 열기"
              aria-expanded={mobileOpen}
              onClick={() => setMobileOpen((prev) => !prev)}
            >
              <span />
              <span />
              <span />
            </button>
          </div>
        </div>
      </header>

      <div
        className={`matey-mobile-overlay ${mobileOpen ? 'is-open' : ''}`}
        onClick={() => setMobileOpen(false)}
        aria-hidden="true"
      />

      <aside className={`matey-mobile-drawer ${mobileOpen ? 'is-open' : ''}`}>
        <div className="matey-mobile-drawer__top">
          <div className="matey-mobile-drawer__brand">
            <div className="matey-mobile-drawer__brand-image">
              <img src="/images/rabbit-duo.png" alt="마음친구 캐릭터" />
            </div>

            <div className="matey-mobile-drawer__brand-text">
              <strong>마음친구</strong>
              <span>먼저 다가가는 AI 친구</span>
            </div>
          </div>

          <button
            type="button"
            className="matey-mobile-drawer__close"
            onClick={() => setMobileOpen(false)}
            aria-label="모바일 메뉴 닫기"
          >
            ×
          </button>
        </div>

        <div className="matey-mobile-drawer__message">
          <strong>오늘 마음은 어떤가요?</strong>
          <p>토끼와 고양이 캐릭터가 홈, 대화, 리포트까지 자연스럽게 안내해줘요.</p>
        </div>

        <nav className="matey-mobile-drawer__nav" aria-label="모바일 메뉴">
          {navItems.map((item) => (
            <a
              key={item.label}
              href={getSectionHref(item.section)}
              className="matey-mobile-drawer__link"
              onClick={() => setMobileOpen(false)}
            >
              <span>{item.label}</span>
              <small>바로 이동</small>
            </a>
          ))}
        </nav>

        <div className="matey-mobile-drawer__bottom">
          {!isLoggedIn && (
            <Link
              to="/login"
              className="matey-header__btn matey-header__btn--ghost matey-mobile-drawer__bottom-btn"
              onClick={() => setMobileOpen(false)}
            >
              로그인
            </Link>
          )}

          <Link
            to={isLoggedIn ? '/chat' : '/signup'}
            className="matey-header__btn matey-header__btn--primary matey-mobile-drawer__bottom-btn"
            onClick={() => setMobileOpen(false)}
          >
            {isLoggedIn ? '대화 시작하기' : '무료 시작하기'}
          </Link>
        </div>
      </aside>
    </>
  );
}
